import scala.collection.mutable

def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {
    val ans = mutable.ArrayBuffer[Long]()
    for (query <- queries) {
        val l = query(0)
        val r = query(1)
        val threshold = query(2)
        val freq = mutable.HashMap[Long, Int]()
        for (i <- l until r + 1) {
            val num = nums(i)
            freq(num) = freq(num) + 1
        }
        var maxCount = -1
        var bestNum = -1
        for ((num, count) <- freq.toList) {
            if (count >= threshold) {
                if (count > maxCount || (count == maxCount && num < bestNum)) {
                    maxCount = count
                    bestNum = num
                }
            }
        }
        ans.append(bestNum)
    }
    ans.toArray
}
