def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {
    val ans = scala.collection.mutable.ArrayBuffer[Long]()
    for (query <- queries) {
        val l = query(0)
        val r = query(1)
        val threshold = query(2)
        val freq = scala.collection.mutable.HashMap[Long, Int]()
        for (i <- l to r) {
            val num = nums(i)
            freq(num) = freq(num) + 1
        }
        val candidates = freq.filter { case (num, count) => count >= threshold }
        val sorted = candidates.toList.sortWith { (a, b) =>
            val countA = a._2
            val countB = b._2
            if (countA != countB) countA > countB else a._1 < b._1
        }
        if (sorted.nonEmpty) {
            ans += sorted.head._1
        } else {
            ans += -1
        }
    }
    ans.toArray
}
